function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  var l = (f.getItemValue('nam') == 0);
  if (l) {
    f.getItem('ky').value = (new Date()).getMonth() + 1;
    f.getItem('nam').value = (new Date()).getFullYear();
  }
  f.live(f.getItem('ky'));
  if (!l) onChange$Report$CostUnit(f.getItem('ma_dvcs'));
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, x = f.getItemValue('mau_bc');
      var d1 = f.getItem('ky').value, n1 = f.getItem('nam').value;
      g._alterTitle = [null, [['%d1', d1, true], ['%n1', n1, true]]];
      break;
    case 'SetReadOnlyField':
      setItemReadOnly(f, 'ma_bp', result[0].Value, false);
      setItemReadOnly(f, 'so_lsx', result[1].Value, false);
      break;
    default:
      break;
  }
}
function onChange$Report$CostUnit(o) {if (o.parentForm._objectUnit == '1') o.parentForm.request('GetResponse', 'SetReadOnlyField', ['ma_dvcs'])}

